+      if (shouldSyncSessions) {
+        await this.syncSessionFiles({ needsFullReindex, progress: progress ?? undefined });
+        this.sessionsDirty = false;
+        this.sessionsDirtyFiles.clear();
+      } else if (this.sessionsDirtyFiles.size > 0) {
